def _resolve_rocm_bin(name, *rel_paths):
    """Resolve a ROCm tool by PATH first, then ROCM_PATH/ROCM_HOME, then /opt/rocm."""
    path = shutil.which(name)
    if path:
        return path
    roots = [os.environ.get("ROCM_PATH"), os.environ.get("ROCM_HOME"), "/opt/rocm"]
    for root in roots:
        if not root:
            continue
        for rel in rel_paths:
            candidate = os.path.join(root, rel)
            if os.path.exists(candidate):
                return candidate
    return name


